const items = $input.first().json.items || [];
const total = $input.first().json.total || 0;

const rows = items.map((o, i) => {
  const deadline = o.deadline || 'sin fecha';
  const score = o.score_total ?? '-';
  const amount = o.amount_max_cop
    ? (o.amount_max_cop >= 1e9
        ? `COP $${(o.amount_max_cop/1e9).toFixed(1)}B`
        : `COP $${Math.round(o.amount_max_cop/1e6)}M`)
    : '-';
  return `<tr>
    <td style="padding:8px;border-bottom:1px solid #eee">${i+1}</td>
    <td style="padding:8px;border-bottom:1px solid #eee"><b>${o.title}</b><br/><span style="color:#666">${o.source_name || ''}</span></td>
    <td style="padding:8px;border-bottom:1px solid #eee;text-align:center"><b>${score}</b>/10</td>
    <td style="padding:8px;border-bottom:1px solid #eee">${amount}</td>
    <td style="padding:8px;border-bottom:1px solid #eee">${deadline}</td>
  </tr>`;
}).join('');

const html = `<div style="font-family:system-ui,sans-serif;max-width:680px;margin:0 auto">
  <h2 style="color:#22D3A0">📊 GrantFlow Weekly</h2>
  <p>Top ${items.length} oportunidades GO en pipeline (de ${total} totales).</p>
  <table style="width:100%;border-collapse:collapse;font-size:14px">
    <thead><tr style="background:#f5f5f5">
      <th style="padding:8px;text-align:left">#</th>
      <th style="padding:8px;text-align:left">Oportunidad</th>
      <th style="padding:8px">Score</th>
      <th style="padding:8px;text-align:left">Monto</th>
      <th style="padding:8px;text-align:left">Cierre</th>
    </tr></thead>
    <tbody>${rows}</tbody>
  </table>
  <p style="margin-top:24px;color:#666;font-size:12px">— Generado por GrantFlow AI</p>
</div>`;

return [{ json: { html, count: items.length, total } }];

